import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Login from './pages/Login';

function App() {
  const backgroundStyle = {
    backgroundImage: `linear-gradient(rgba(255, 255, 255, 0.7), rgba(255, 255, 255, 0.7)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?q=80&w=2000')`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundAttachment: 'fixed',
    minHeight: '100vh'
  };

  return (
    <Router>
      <div style={backgroundStyle}>
        {/* Main Navbar jo sarv pages var disel */}
        <nav className="navbar navbar-expand-lg navbar-dark px-4 shadow-sm py-2" style={{ backgroundColor: '#0056b3' }}>
          <div className="container-fluid">
            <Link className="navbar-brand fw-bold" to="/">APNI MANZIL</Link>
            <div className="ms-auto">
              <Link to="/login" className="btn btn-success rounded-pill px-4 fw-bold">Login</Link>
            </div>
          </div>
        </nav>

        {/* Ata Router tharvel konta page dakhvayche */}
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
